INSERT INTO "recruits" ("id","org","deleted","version","updated_at","data") VALUES('rec_mr7oox7n_18','omega-1',0,2,'2026-07-05T11:05:37.729Z','{"id":"rec_mr7oox7n_18","ref":"SCT-0045","name":"Boku","steamId":"STEAM_0:0:126473858","department":"Medical Department","rank":"GSD Containment Unit / Combat Medic","org":"omega-1","stage":"scouting","archiveStatus":null,"archiveReason":null,"applicationLink":"","tag":null,"comments":[{"id":"rc_mr7oox7n_19","by":"O1-1","ts":"2026-07-05T11:04:29.987Z","stage":"scouting","text":"Scouting target opened by O1-1."},{"id":"rc_mr7oqdqi_1k","by":"O1-1","ts":"2026-07-05T11:05:38.058Z","stage":"scouting","text":"~•~ O-1 Operative Name: ''Baker'' [635] Scouted Individual: Boku ~•~ Scenario Initiated: Background check Response: Joined the foundation at age 16 with family ties to CI as his father was a insurgent. Father is dead due to a site raid. He was previously a exec RSD in a site in France where he fell into the medical field and became a Combat medic.  Scenario Initiated: KH run Response: Did somewhat well with desent times but missed a target right in front of him due to rushing. handled smoke and flashbangs quite well on his KH run but got semi flashed near the end. On the 3rd run he had to find a doll mid run and he cleared the coarse then tried to find the package what was quite good.  Scenario Initiated: FLC violation Response: I did drugs in Dblock and offered some to him where he then downed the entire glass. He did not care that it was a FLC violation. AND DID NOT EVEN ASK WHAT IT WAS.  General Observations: Rushes things but gets the job done sometimes missing very important things. ~•~ Notes: N/A"}],"votes":{},"tryoutStrikes":[],"personnelFileId":null,"createdBy":"O1-1","createdAt":"2026-07-05T11:04:29.987Z","updatedAt":"2026-07-05T11:05:37.729Z","version":2,"deleted":false,"deletedAt":null}');
